          >
            <span className="flex items-center gap-2">
              <div className="w-2 h-2 bg-blue-500" />
              Kalshi
            </span>
          </button>
        </div>

        <div className="flex items-center gap-2">
          <span className="text-[11px] text-zinc-600 font-mono">
            {lastUpdated.toLocaleTimeString()}
