import { Trader } from "../types";
import { formatCurrency, formatVolume } from "../lib/data";
import { TrendingUp, Trophy, Medal, Award } from "lucide-react";
import { motion } from "framer-motion";

interface TraderRowProps {
  trader: Trader;
  index: number;
  platform: "polymarket" | "kalshi";
}

function RankBadge({ rank }: { rank: number }) {
  if (rank === 1) {
    return (
      <div className="flex items-center justify-center w-8 h-8 bg-yellow-500/20 text-yellow-400">
        <Trophy size={16} />
      </div>
    );
  }
  if (rank === 2) {
    return (
      <div className="flex items-center justify-center w-8 h-8 bg-zinc-400/20 text-zinc-300">
        <Medal size={16} />
      </div>
    );
  }
  if (rank === 3) {
    return (
      <div className="flex items-center justify-center w-8 h-8 bg-orange-500/20 text-orange-400">
        <Award size={16} />
      </div>
    );
  }
  return (
    <div className="flex items-center justify-center w-8 h-8 text-zinc-500 font-mono text-sm">
      {rank}
    </div>
  );
}

export default function TraderRow({ trader, index, platform }: TraderRowProps) {
  const pnlColor = trader.pnl >= 0 ? "text-emerald-400" : "text-red-400";
  const winRateColor =
    trader.winRate >= 80
      ? "text-emerald-400"
      : trader.winRate >= 70
      ? "text-yellow-400"
      : trader.winRate >= 60
      ? "text-orange-400"
      : "text-red-400";

  const platformColor =
    platform === "polymarket" ? "bg-violet-500" : "bg-blue-500";

  return (
    <motion.tr
      initial={{ opacity: 0, y: 8 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.2, delay: index * 0.03 }}
      className="border-b border-zinc-800/50 hover:bg-zinc-800/30 transition-colors group"
    >
      <td className="py-2.5 px-2">
        <RankBadge rank={trader.rank} />
      </td>
      <td className="py-2.5 px-2">
        <div className="flex items-center gap-2">
          <div
            className={`w-6 h-6 ${platformColor} flex items-center justify-center text-[10px] font-bold text-white shrink-0`}
          >
            {trader.name.charAt(0).toUpperCase()}
          </div>
          <span className="text-zinc-100 text-sm font-medium truncate max-w-[140px] group-hover:text-white transition-colors">
            {trader.name}
          </span>
        </div>
      </td>
      <td className={`py-2.5 px-2 text-right text-sm font-mono font-semibold ${pnlColor}`}>
        {trader.pnl >= 0 ? "+" : ""}
        {formatCurrency(trader.pnl)}
      </td>
      <td className="py-2.5 px-2 text-right text-sm font-mono text-zinc-400">
        {formatVolume(trader.volume)}
      </td>
      <td className="py-2.5 px-2 text-right text-sm font-mono text-zinc-400 hidden sm:table-cell">
        {trader.marketsTraded}
      </td>
      <td className={`py-2.5 px-2 text-right text-sm font-mono hidden sm:table-cell ${winRateColor}`}>
        {trader.winRate.toFixed(1)}%
      </td>
      <td className="py-2.5 px-2 text-right text-sm font-mono text-zinc-500 hidden md:table-cell">
        {trader.positions}
      </td>
    </motion.tr>
  );
}

